class Solution {
    public String solveEquation(String equation) {
        String[] parts = equation.split("=");
        String left = parts[0];
        String right = parts[1];
        int xLeft = 0;
        int constantLeft = 0;
        int xRight = 0;
        int constantRight = 0;
        for (String term : left.split("[\\+\\-]")) {
            if (term.equals("x")) {
                xLeft++;
            } else {
                constantLeft += Integer.parseInt(term);
            }
        }
        for (String term : right.split("[\\+\\-]")) {
            if (term.equals("x")) {
                xRight++;
            } else {
                constantRight += Integer.parseInt(term);
            }
        }
        if (xLeft == xRight) {
            if (constantLeft == constantRight) {
                return "Infinite solutions";
            } else {
                return "No solution";
            }
        } else {
            int x = (constantRight - constantLeft) / (xLeft - xRight);
            return "x=" + x;
        }
    }
}
